//! AppState — owns canvas, active tool, and handles events
//!
//! This is the core application state that bridges SDL2 events
//! to domain operations on the canvas.

use undo::Record;

use crate::canvas::Canvas;
use crate::commands::{AddLayer, CanvasCommand};
use crate::events::AppEvent;
use crate::tools::{BrushTool, Tool};
use crate::viewport::ViewportState;

/// Application state containing all mutable application data
pub struct AppState {
    canvas: Canvas,
    active_tool: Box<dyn Tool>,
    history: Record<CanvasCommand>,
    viewport: ViewportState,
}

impl AppState {
    /// Create a new AppState with default canvas and brush tool
    pub fn new(width: u32, height: u32) -> Self {
        let mut canvas = Canvas::new();
        // Initialize canvas with given dimensions
        canvas.resize(width, height);

        Self {
            viewport: ViewportState::new(width, height, width, height),
            canvas,
            active_tool: Box::new(BrushTool::new()),
            history: Record::new(),
        }
    }

    /// Get a reference to the canvas
    pub fn canvas(&self) -> &Canvas {
        &self.canvas
    }

    /// Get the viewport width (window width)
    pub fn viewport_width(&self) -> u32 {
        self.viewport.window_width
    }

    /// Get the viewport height (window height)
    pub fn viewport_height(&self) -> u32 {
        self.viewport.window_height
    }

    /// Get a reference to the viewport state
    pub fn viewport(&self) -> &ViewportState {
        &self.viewport
    }

    /// Get a mutable reference to the viewport state
    pub fn viewport_mut(&mut self) -> &mut ViewportState {
        &mut self.viewport
    }

    /// Get a mutable reference to the canvas
    pub fn canvas_mut(&mut self) -> &mut Canvas {
        &mut self.canvas
    }

    /// Get a mutable reference to the undo history
    pub fn history_mut(&mut self) -> &mut Record<CanvasCommand> {
        &mut self.history
    }

    /// Get the name of the active tool
    pub fn tool_name(&self) -> &str {
        self.active_tool.name()
    }

    /// Get an immutable reference to the active tool
    pub fn active_tool(&self) -> &dyn Tool {
        self.active_tool.as_ref()
    }

    /// Get a mutable reference to the active tool as a trait object
    pub fn active_tool_mut(&mut self) -> &mut dyn Tool {
        self.active_tool.as_mut()
    }

    /// Set the active tool
    pub fn set_active_tool(&mut self, tool: Box<dyn Tool>) {
        self.active_tool = tool;
    }

    /// Check if undo is available
    pub fn can_undo(&self) -> bool {
        self.history.can_undo()
    }

    /// Check if redo is available
    pub fn can_redo(&self) -> bool {
        self.history.can_redo()
    }

    /// Handle an application event
    pub fn handle_event(&mut self, event: AppEvent) {
        match event {
            AppEvent::Press { x, y } => {
                if let Some((cx, cy)) = self.viewport.screen_to_canvas(x, y) {
                    self.active_tool.on_press(cx, cy, &mut self.canvas);
                }
            }
            AppEvent::Drag { x, y } => {
                if let Some((cx, cy)) = self.viewport.screen_to_canvas(x, y) {
                    self.active_tool.on_drag(cx, cy, &mut self.canvas);
                }
            }
            AppEvent::Release { x, y } => {
                if let Some((cx, cy)) = self.viewport.screen_to_canvas(x, y) {
                    self.active_tool.on_release(cx, cy, &mut self.canvas);
                }
            }
            AppEvent::Key { code } => {
                self.handle_key(&code);
            }
            AppEvent::Resize { width, height } => {
                self.viewport.resize_window(width, height);
            }
            AppEvent::Wheel { x, y, delta } => {
                let factor = if delta > 0 { crate::viewport::ZOOM_FACTOR } else { 1.0 / crate::viewport::ZOOM_FACTOR };
                self.viewport.zoom_toward(x, y, factor);
            }
            AppEvent::Pan { dx, dy } => {
                self.viewport.pan(dx, dy);
            }
            AppEvent::Quit => {
                // Handled by SDL2 loop
            }
        }
    }

    fn handle_key(&mut self, code: &str) {
        match code {
            "z" => {
                if self.history.can_undo() {
                    self.history.undo(&mut self.canvas);
                }
            }
            "y" => {
                if self.history.can_redo() {
                    self.history.redo(&mut self.canvas);
                }
            }
            _ => {
                self.active_tool.on_key(code);
            }
        }
    }

    /// Add a new layer through the undo system
    pub fn add_layer(&mut self) {
        let _ = self.history.edit(&mut self.canvas, CanvasCommand::AddLayer(AddLayer::default()));
    }

    /// Undo the last action
    pub fn undo(&mut self) {
        if self.history.can_undo() {
            self.history.undo(&mut self.canvas);
        }
    }

    /// Redo the last undone action
    pub fn redo(&mut self) {
        if self.history.can_redo() {
            self.history.redo(&mut self.canvas);
        }
    }

    /// Execute a canvas command through the undo system
    pub fn execute_command(&mut self, command: CanvasCommand) {
        let _ = self.history.edit(&mut self.canvas, command);
    }
}

//! Tests for Phase 3: Tool trait + AppEvent + AppState

#[test]
fn app_event_press_contains_position() {
    use crate::events::AppEvent;
    let evt = AppEvent::Press { x: 100.0, y: 200.0 };
    match evt {
        AppEvent::Press { x, y } => {
            assert_eq!(x, 100.0);
            assert_eq!(y, 200.0);
        }
        _ => panic!("expected Press event"),
    }
}

#[test]
fn app_event_drag_contains_deltas() {
    use crate::events::AppEvent;
    let evt = AppEvent::Drag { x: 50.0, y: 75.0 };
    match evt {
        AppEvent::Drag { x, y } => {
            assert_eq!(x, 50.0);
            assert_eq!(y, 75.0);
        }
        _ => panic!("expected Drag event"),
    }
}

#[test]
fn app_event_release_is_constructed() {
    use crate::events::AppEvent;
    let evt = AppEvent::Release { x: 300.0, y: 400.0 };
    match evt {
        AppEvent::Release { x, y } => {
            assert_eq!(x, 300.0);
            assert_eq!(y, 400.0);
        }
        _ => panic!("expected Release event"),
    }
}

#[test]
fn app_state_has_canvas() {
    use crate::app::AppState;
    let state = AppState::new(1280, 720);
    assert!(state.canvas().layers().len() > 0);
}

#[test]
fn app_state_has_active_tool() {
    use crate::app::AppState;
    let state = AppState::new(1280, 720);
    assert!(state.tool_name() == "Brush");
}

#[test]
fn app_state_handle_press_modifies_canvas() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    state.handle_event(AppEvent::Press { x: 10.0, y: 10.0 });
    // Press event should be handled without error
    // The canvas state may change (stroke started, etc.)
}

#[test]
fn app_state_handle_drag_updates_state() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    state.handle_event(AppEvent::Press { x: 10.0, y: 10.0 });
    state.handle_event(AppEvent::Drag { x: 20.0, y: 20.0 });
    // Drag after press should work
}

#[test]
fn app_state_handle_release_completes_stroke() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    state.handle_event(AppEvent::Press { x: 10.0, y: 10.0 });
    state.handle_event(AppEvent::Drag { x: 20.0, y: 20.0 });
    state.handle_event(AppEvent::Release { x: 30.0, y: 30.0 });
    // Release should complete the stroke
}

#[test]
fn app_state_undo_redo_via_keyboard() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    assert!(!state.can_undo());

    // Add a layer
    state.add_layer();
    assert_eq!(state.canvas().layers.len(), 2);
    assert!(state.can_undo());

    // Undo via key
    state.handle_event(AppEvent::Key { code: "z".to_string() });
    assert_eq!(state.canvas().layers.len(), 1);
    assert!(!state.can_undo());
    assert!(state.can_redo());

    // Redo via key
    state.handle_event(AppEvent::Key { code: "y".to_string() });
    assert_eq!(state.canvas().layers.len(), 2);
}

#[test]
fn app_state_resize_does_not_change_canvas_size() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    let (orig_w, orig_h) = state.canvas().size();

    state.handle_event(AppEvent::Resize { width: 800, height: 600 });

    assert_eq!(state.canvas().size(), (orig_w, orig_h));
    assert_eq!(state.canvas().width(), 1280);
    assert_eq!(state.canvas().height(), 720);
}

#[test]
fn app_state_tracks_viewport_size_after_resize() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    assert_eq!(state.viewport_width(), 1280);
    assert_eq!(state.viewport_height(), 720);

    state.handle_event(AppEvent::Resize { width: 1920, height: 1080 });

    assert_eq!(state.viewport_width(), 1920);
    assert_eq!(state.viewport_height(), 1080);
    // Canvas should still be original size
    assert_eq!(state.canvas().width(), 1280);
    assert_eq!(state.canvas().height(), 720);
}

#[test]
fn app_state_undo_redo_methods() {
    use crate::app::AppState;

    let mut state = AppState::new(1280, 720);
    state.add_layer();
    assert_eq!(state.canvas().layers.len(), 2);

    state.undo();
    assert_eq!(state.canvas().layers.len(), 1);

    state.redo();
    assert_eq!(state.canvas().layers.len(), 2);
}

#[test]
fn app_event_wheel_contains_position_and_delta() {
    use crate::events::AppEvent;
    let evt = AppEvent::Wheel { x: 100.0, y: 200.0, delta: 1 };
    match evt {
        AppEvent::Wheel { x, y, delta } => {
            assert_eq!(x, 100.0);
            assert_eq!(y, 200.0);
            assert_eq!(delta, 1);
        }
        _ => panic!("expected Wheel event"),
    }
}

#[test]
fn app_event_pan_contains_deltas() {
    use crate::events::AppEvent;
    let evt = AppEvent::Pan { dx: 10.0, dy: 20.0 };
    match evt {
        AppEvent::Pan { dx, dy } => {
            assert_eq!(dx, 10.0);
            assert_eq!(dy, 20.0);
        }
        _ => panic!("expected Pan event"),
    }
}

#[test]
fn pan_event_moves_viewport_offset() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    let before_x = state.viewport().offset_x;
    let before_y = state.viewport().offset_y;

    state.handle_event(AppEvent::Pan { dx: 50.0, dy: 30.0 });

    assert!((state.viewport().offset_x - before_x - 50.0).abs() < 1e-6);
    assert!((state.viewport().offset_y - before_y - 30.0).abs() < 1e-6);
}

#[test]
fn wheel_event_zooms_in() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    let orig_scale = state.viewport().scale;

    state.handle_event(AppEvent::Wheel { x: 640.0, y: 360.0, delta: 1 });

    assert!(state.viewport().scale > orig_scale);
}

#[test]
fn wheel_event_zooms_out() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    state.viewport_mut().scale = 2.0;
    let orig_scale = state.viewport().scale;

    state.handle_event(AppEvent::Wheel { x: 640.0, y: 360.0, delta: -1 });

    assert!(state.viewport().scale < orig_scale);
}

#[test]
fn app_state_press_at_centered_viewport_maps_to_canvas_coord() {
    use crate::app::AppState;
    use crate::events::AppEvent;

    let mut state = AppState::new(1280, 720);
    // Resize viewport larger than canvas to trigger centering
    state.handle_event(AppEvent::Resize { width: 1920, height: 1080 });

    // Screen (400, 200) → canvas (80, 20) when canvas is centered in 1920x1080
    state.handle_event(AppEvent::Press { x: 400.0, y: 200.0 });

    let layer = &state.canvas().layers()[state.canvas().active_layer()];
    let pixel = layer.content.get_pixel(80, 20);
    assert!(pixel.is_some_and(|(_, _, _, a)| a > 0));
}

//! DabMask: 2D pixel mask for brush tips
//!
//! Each DabMask is a small RGBA bitmap representing the brush tip shape.
//! Alpha values determine how much each pixel is affected when stamping.

#[derive(Debug, Clone, PartialEq)]
pub struct DabMask {
    pub width: u32,
    pub height: u32,
    pub data: Vec<u8>,
}

impl DabMask {
    pub fn new(size: u32) -> Self {
        let size = size.max(1);
        Self {
            width: size,
            height: size,
            data: vec![255; (size * size * 4) as usize],
        }
    }

    pub fn get_alpha(&self, x: u32, y: u32) -> u8 {
        if x >= self.width || y >= self.height {
            return 0;
        }
        let idx = ((y * self.width + x) * 4 + 3) as usize;
        self.data.get(idx).copied().unwrap_or(0)
    }

    pub fn set_alpha(&mut self, x: u32, y: u32, alpha: u8) {
        if x >= self.width || y >= self.height {
            return;
        }
        let idx = ((y * self.width + x) * 4 + 3) as usize;
        if let Some(v) = self.data.get_mut(idx) {
            *v = alpha;
        }
    }

    pub fn dimensions(&self) -> (u32, u32) {
        (self.width, self.height)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_dab_mask_creates_square_buffer() {
        let dab = DabMask::new(3);
        assert_eq!(dab.width, 3);
        assert_eq!(dab.height, 3);
        assert_eq!(dab.data.len(), 36);
    }

    #[test]
    fn test_dab_mask_get_alpha_returns_full_opacity_by_default() {
        let dab = DabMask::new(2);
        assert_eq!(dab.get_alpha(0, 0), 255);
        assert_eq!(dab.get_alpha(1, 1), 255);
    }

    #[test]
    fn test_dab_mask_get_alpha_returns_zero_for_out_of_bounds() {
        let dab = DabMask::new(2);
        assert_eq!(dab.get_alpha(5, 0), 0);
        assert_eq!(dab.get_alpha(0, 5), 0);
    }

    #[test]
    fn test_dab_mask_set_alpha_updates_pixel() {
        let mut dab = DabMask::new(2);
        dab.set_alpha(0, 0, 128);
        assert_eq!(dab.get_alpha(0, 0), 128);
    }

    #[test]
    fn test_dab_mask_set_alpha_ignores_out_of_bounds() {
        let mut dab = DabMask::new(2);
        dab.set_alpha(5, 5, 128);
        assert_eq!(dab.get_alpha(5, 5), 0);
    }

    #[test]
    fn test_dab_mask_clamped_to_minimum_size() {
        let dab = DabMask::new(0);
        assert_eq!(dab.width, 1);
        assert_eq!(dab.height, 1);
    }
}

//! BrushEngine - applies dabs to raster images
//!
//! Stamps brush dabs onto RasterImage buffers with alpha compositing.

use crate::brush::DabMask;
use crate::canvas::{RasterImage, Color};

pub struct BrushEngine;

impl BrushEngine {
    fn apply_dab<F>(buffer: &mut RasterImage, cx: i32, cy: i32, dab: &DabMask, mut pixel_op: F)
    where
        F: FnMut(u8, &mut crate::canvas::PixelRef),
    {
        let dab_w = dab.width as i32;
        let dab_h = dab.height as i32;
        let offset_x = cx - dab_w / 2;
        let offset_y = cy - dab_h / 2;

        for dy in 0..dab_h {
            for dx in 0..dab_w {
                let dab_alpha = dab.get_alpha(dx as u32, dy as u32);
                if dab_alpha == 0 {
                    continue;
                }

                let buf_x = offset_x + dx;
                let buf_y = offset_y + dy;

                if buf_x < 0 || buf_y < 0 {
                    continue;
                }
                if buf_x >= buffer.width as i32 || buf_y >= buffer.height as i32 {
                    continue;
                }

                if let Some(mut pixel) = buffer.get_pixel_mut(buf_x as u32, buf_y as u32) {
                    pixel_op(dab_alpha, &mut pixel);
                }
            }
        }
    }

    pub fn stamp_dab(
        buffer: &mut RasterImage,
        cx: i32,
        cy: i32,
        dab: &DabMask,
        color: Color,
    ) {
        let final_alpha_mul = color.a as f32 / 255.0;
        Self::apply_dab(buffer, cx, cy, dab, |dab_alpha, pixel| {
            let final_alpha = ((dab_alpha as f32 / 255.0) * final_alpha_mul * 255.0) as u8;
            let src_a = final_alpha as f32 / 255.0;
            pixel.set_r(((color.r as f32 * src_a) + (pixel.r() as f32 * (1.0 - src_a))) as u8);
            pixel.set_g(((color.g as f32 * src_a) + (pixel.g() as f32 * (1.0 - src_a))) as u8);
            pixel.set_b(((color.b as f32 * src_a) + (pixel.b() as f32 * (1.0 - src_a))) as u8);
            pixel.set_a((pixel.a() as u16 + final_alpha as u16).min(255) as u8);
        });
    }

    pub fn erase_dab(
        buffer: &mut RasterImage,
        cx: i32,
        cy: i32,
        dab: &DabMask,
        bg_color: Color,
        erase_opacity: f32,
    ) {
        Self::apply_dab(buffer, cx, cy, dab, |dab_alpha, pixel| {
            let erase_strength = (dab_alpha as f32 / 255.0) * erase_opacity;
            let new_a = (pixel.a() as f32 * (1.0 - erase_strength)) as u8;
            pixel.set_a(new_a);
            if new_a == 0 {
                pixel.set_r(bg_color.r);
                pixel.set_g(bg_color.g);
                pixel.set_b(bg_color.b);
            }
        });
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::brush::RoundDab;

    #[test]
    fn test_stamp_dab_affects_pixels_at_center() {
        let mut buffer = RasterImage::new(10, 10);
        let dab = RoundDab::generate(3);
        let color = Color { r: 255, g: 0, b: 0, a: 255 };

        BrushEngine::stamp_dab(&mut buffer, 5, 5, &dab, color);

        let px = buffer.get_pixel(5, 5).unwrap();
        assert!(px.0 > 0);
    }

    #[test]
    fn test_stamp_dab_does_not_affect_distant_pixels() {
        let mut buffer = RasterImage::new(10, 10);
        let dab = RoundDab::generate(3);
        let color = Color { r: 255, g: 0, b: 0, a: 255 };

        BrushEngine::stamp_dab(&mut buffer, 0, 0, &dab, color);

        let px = buffer.get_pixel(5, 5).unwrap();
        assert_eq!(px.0, 0);
    }

    #[test]
    fn test_stamp_dab_respects_partial_transparency() {
        let mut buffer = RasterImage::new(10, 10);
        let dab = RoundDab::generate(3);
        let color = Color { r: 255, g: 0, b: 0, a: 128 };

        BrushEngine::stamp_dab(&mut buffer, 5, 5, &dab, color);

        let px = buffer.get_pixel(5, 5).unwrap();
        assert!(px.0 > px.1);
        assert!(px.0 < 255);
    }

    #[test]
    fn test_stamp_dab_out_of_bounds_is_ignored() {
        let mut buffer = RasterImage::new(10, 10);
        let dab = RoundDab::generate(20);
        let color = Color { r: 255, g: 0, b: 0, a: 255 };

        BrushEngine::stamp_dab(&mut buffer, -5, -5, &dab, color);
    }

    #[test]
    fn test_draw_line_produces_continuous_pixels() {
        let mut buffer = RasterImage::new(20, 20);
        let dab = RoundDab::generate(3);
        let color = Color { r: 50, g: 50, b: 50, a: 200 };

        for t in [0.0_f32, 0.5, 1.0] {
            let x = (0.0 + (10.0 - 0.0) * t) as i32;
            let y = (0.0 + (10.0 - 0.0) * t) as i32;
            BrushEngine::stamp_dab(&mut buffer, x, y, &dab, color);
        }

        let px = buffer.get_pixel(0, 0).unwrap();
        assert!(px.0 > 0);
        let px = buffer.get_pixel(10, 10).unwrap();
        assert!(px.0 > 0);
    }

    #[test]
    fn test_small_dab_does_not_panic() {
        let mut buffer = RasterImage::new(3, 3);
        let dab = RoundDab::generate(1);
        BrushEngine::stamp_dab(&mut buffer, 1, 1, &dab, Color { r: 100, g: 100, b: 100, a: 200 });
    }
}

//! Brush engine module
//!
//! CPU-based dab painting system for raster canvas drawing.

pub mod dab;
pub mod round;
pub mod engine;

pub use dab::DabMask;
pub use round::RoundDab;
pub use engine::BrushEngine;

/// Available brush types
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum BrushType {
    Round,
    Square,
}

//! Round dab - antialiased circular brush tip

use crate::brush::DabMask;

pub struct RoundDab;

impl RoundDab {
    pub fn generate(size: u32) -> DabMask {
        if size <= 2 {
            return DabMask::new(size);
        }

        let mut dab = DabMask::new(size);
        let cx = size as f32 / 2.0;
        let cy = size as f32 / 2.0;
        let radius = (size as f32 - 1.0) / 2.0;
        let radius_sq = radius * radius;

        for y in 0..size {
            for x in 0..size {
                let dx = x as f32 - cx;
                let dy = y as f32 - cy;
                let dist_sq = dx * dx + dy * dy;
                let alpha = if dist_sq <= radius_sq {
                    let dist = dist_sq.sqrt();
                    let edge_dist = radius - dist;
                    ((edge_dist / radius) * 255.0) as u8
                } else {
                    0
                };
                dab.set_alpha(x, y, alpha);
            }
        }
        dab
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_round_dab_center_has_high_opacity() {
        let dab = RoundDab::generate(5);
        let alpha = dab.get_alpha(2, 2);
        assert!(alpha > 128);
    }

    #[test]
    fn test_round_dab_corners_have_zero_opacity() {
        let dab = RoundDab::generate(5);
        assert_eq!(dab.get_alpha(0, 0), 0);
        assert_eq!(dab.get_alpha(4, 4), 0);
    }

    #[test]
    fn test_round_dab_edge_pixels_are_antialiased() {
        let dab = RoundDab::generate(5);
        let center_alpha = dab.get_alpha(2, 2);
        let corner_alpha = dab.get_alpha(0, 0);
        assert!(center_alpha > corner_alpha);
        assert!(center_alpha > 0);
        assert_eq!(corner_alpha, 0);
    }

    #[test]
    fn test_round_dab_small_size() {
        let dab = RoundDab::generate(1);
        assert!(dab.get_alpha(0, 0) > 0);
    }
}

//! Canvas module for Rancer
//!
//! Provides the core canvas functionality using raster layers.

use serde::{Deserialize, Serialize};

/// Represents a 2D point in canvas space
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Point {
    pub x: f32,
    pub y: f32,
}

/// Represents a color in RGBA format
#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
pub struct Color {
    pub r: u8,
    pub g: u8,
    pub b: u8,
    pub a: u8,
}

impl Color {
    pub const WHITE: Self = Self { r: 255, g: 255, b: 255, a: 255 };
    pub const BLACK: Self = Self { r: 0, g: 0, b: 0, a: 255 };
    pub const TRANSPARENT: Self = Self { r: 0, g: 0, b: 0, a: 0 };
}

pub const MAX_CUSTOM_COLORS: usize = 10;

/// Represents HSV color values (Hue, Saturation, Value)
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct HsvColor {
    pub h: f32,
    pub s: f32,
    pub v: f32,
}

impl Default for HsvColor {
    fn default() -> Self {
        Self { h: 0.0, s: 100.0, v: 100.0 }
    }
}

impl HsvColor {
    pub fn new(h: f32, s: f32, v: f32) -> Self {
        Self { h, s, v }
    }

    pub fn to_rgb(&self) -> Color {
        hsv_to_rgb(self.h, self.s, self.v)
    }
}

pub fn hsv_to_rgb(h: f32, s: f32, v: f32) -> Color {
    let s = s / 100.0;
    let v = v / 100.0;
    let h_norm = h / 60.0;
    let i = h_norm.floor() as i32 % 6;
    let f = h_norm - h_norm.floor();
    let p = v * (1.0 - s);
    let q = v * (1.0 - s * f);
    let t = v * (1.0 - s * (1.0 - f));

    let (r, g, b) = match i {
        0 => (v, t, p),
        1 => (q, v, p),
        2 => (p, v, t),
        3 => (p, q, v),
        4 => (t, p, v),
        _ => (v, p, q),
    };

    Color {
        r: (r * 255.0).round() as u8,
        g: (g * 255.0).round() as u8,
        b: (b * 255.0).round() as u8,
        a: 255,
    }
}

pub fn rgb_to_hsv(color: Color) -> HsvColor {
    let r = color.r as f32 / 255.0;
    let g = color.g as f32 / 255.0;
    let b = color.b as f32 / 255.0;
    let max = r.max(g).max(b);
    let min = r.min(g).min(b);
    let delta = max - min;

    let v = max * 100.0;
    let s = if max.abs() < f32::EPSILON {
        0.0
    } else {
        delta / max * 100.0
    };
    let h = if delta.abs() < f32::EPSILON {
        0.0
    } else if (max - r).abs() < f32::EPSILON {
        60.0 * (((g - b) / delta) % 6.0)
    } else if (max - g).abs() < f32::EPSILON {
        60.0 * ((b - r) / delta + 2.0)
    } else {
        60.0 * ((r - g) / delta + 4.0)
    };

    HsvColor { h, s, v }
}

/// Pixel reference for mutable access
pub struct PixelRef<'a> {
    data: &'a mut [u8],
}

impl<'a> PixelRef<'a> {
    pub fn r(&self) -> u8 { self.data[0] }
    pub fn g(&self) -> u8 { self.data[1] }
    pub fn b(&self) -> u8 { self.data[2] }
    pub fn a(&self) -> u8 { self.data[3] }

    pub fn set_r(&mut self, r: u8) { self.data[0] = r; }
    pub fn set_g(&mut self, g: u8) { self.data[1] = g; }
    pub fn set_b(&mut self, b: u8) { self.data[2] = b; }
    pub fn set_a(&mut self, a: u8) { self.data[3] = a; }
}

/// Raster image data (RGBA pixels)
#[derive(Debug, Clone)]
pub struct RasterImage {
    pub width: u32,
    pub height: u32,
    pub data: Vec<u8>,
}

impl RasterImage {
    pub fn new(width: u32, height: u32) -> Self {
        Self {
            width,
            height,
            data: vec![0; (width * height * 4) as usize],
        }
    }

    pub fn get_pixel(&self, x: u32, y: u32) -> Option<(u8, u8, u8, u8)> {
        if x >= self.width || y >= self.height {
            return None;
        }
        let idx = ((y * self.width + x) * 4) as usize;
        Some((
            self.data[idx],
            self.data[idx + 1],
            self.data[idx + 2],
            self.data[idx + 3],
        ))
    }

    pub fn set_pixel(&mut self, x: u32, y: u32, r: u8, g: u8, b: u8, a: u8) {
        if x >= self.width || y >= self.height {
            return;
        }
        let idx = ((y * self.width + x) * 4) as usize;
        self.data[idx] = r;
        self.data[idx + 1] = g;
        self.data[idx + 2] = b;
        self.data[idx + 3] = a;
    }

    pub fn get_pixel_mut(&mut self, x: u32, y: u32) -> Option<PixelRef<'_>> {
        if x >= self.width || y >= self.height {
            return None;
        }
        let idx = ((y * self.width + x) * 4) as usize;
        Some(PixelRef { data: &mut self.data[idx..idx + 4] })
    }

    pub fn resize(&mut self, width: u32, height: u32) {
        self.width = width;
        self.height = height;
        self.data.resize((width * height * 4) as usize, 0);
    }

    pub fn fill(&mut self, color: Color) {
        let bytes = [color.r, color.g, color.b, color.a];
        for chunk in self.data.chunks_exact_mut(4) {
            chunk.copy_from_slice(&bytes);
        }
    }
}

#[cfg(test)]
mod pixel_ref_tests {
    use super::*;

    #[test]
    fn test_pixel_ref_reads_correct_values() {
        let mut image = RasterImage::new(2, 2);
        image.set_pixel(0, 0, 10, 20, 30, 40);

        if let Some(pixel) = image.get_pixel_mut(0, 0) {
            assert_eq!(pixel.r(), 10);
            assert_eq!(pixel.g(), 20);
            assert_eq!(pixel.b(), 30);
            assert_eq!(pixel.a(), 40);
        } else {
            panic!("Expected pixel");
        }
    }

    #[test]
    fn test_pixel_ref_writes_correct_values() {
        let mut image = RasterImage::new(2, 2);

        if let Some(mut pixel) = image.get_pixel_mut(0, 0) {
            pixel.set_r(100);
            pixel.set_g(150);
            pixel.set_b(200);
            pixel.set_a(250);
        }

        assert_eq!(image.get_pixel(0, 0), Some((100, 150, 200, 250)));
    }

    #[test]
    fn test_pixel_ref_returns_none_for_out_of_bounds() {
        let mut image = RasterImage::new(2, 2);
        assert!(image.get_pixel_mut(5, 0).is_none());
        assert!(image.get_pixel_mut(0, 5).is_none());
    }
}

/// Represents a single layer in the canvas (raster only)
#[derive(Debug, Clone)]
pub struct Layer {
    pub name: String,
    pub content: RasterImage,
    pub visible: bool,
    pub opacity: f32,
    pub locked: bool,
}

impl Default for Layer {
    fn default() -> Self {
        Self {
            name: "Layer 1".to_string(),
            content: RasterImage::new(1280, 720),
            visible: true,
            opacity: 1.0,
            locked: false,
        }
    }
}

impl Layer {
    pub fn new(name: String, width: u32, height: u32, opacity: f32) -> Self {
        Self {
            name,
            content: RasterImage::new(width, height),
            visible: true,
            opacity,
            locked: false,
        }
    }

    pub fn content_mut(&mut self) -> &mut RasterImage {
        &mut self.content
    }

    pub fn content(&self) -> &RasterImage {
        &self.content
    }

    pub fn clear(&mut self) {
        self.content.fill(Color::TRANSPARENT);
    }
}

/// The main canvas for drawing operations
#[derive(Clone)]
pub struct Canvas {
    pub(crate) width: u32,
    pub(crate) height: u32,
    pub(crate) background_color: Color,
    pub(crate) layers: Vec<Layer>,
    pub(crate) active_layer: usize,
    pub(crate) version: u64,
    dirty_rect: DirtyRect,
}

/// Rectangle representing a dirty region
#[derive(Debug, Clone, Copy)]
pub struct DirtyRect {
    pub x: u32,
    pub y: u32,
    pub width: u32,
    pub height: u32,
    is_dirty: bool,
}

impl DirtyRect {
    pub fn new() -> Self {
        Self {
            x: 0,
            y: 0,
            width: 0,
            height: 0,
            is_dirty: false,
        }
    }

    pub fn is_empty(&self) -> bool {
        !self.is_dirty
    }

    pub fn contains(&self, x: u32, y: u32) -> bool {
        self.is_dirty && x >= self.x && x < self.x + self.width && y >= self.y && y < self.y + self.height
    }

    pub fn mark_pixel(&mut self, x: u32, y: u32) {
        if !self.is_dirty {
            self.x = x;
            self.y = y;
            self.width = 1;
            self.height = 1;
            self.is_dirty = true;
        } else {
            let new_min_x = self.x.min(x);
            let new_min_y = self.y.min(y);
            let new_max_x = (self.x + self.width).max(x + 1);
            let new_max_y = (self.y + self.height).max(y + 1);
            self.x = new_min_x;
            self.y = new_min_y;
            self.width = new_max_x - new_min_x;
            self.height = new_max_y - new_min_y;
        }
    }

    pub fn mark_rect(&mut self, x: u32, y: u32, w: u32, h: u32) {
        if w == 0 || h == 0 {
            return;
        }
        if !self.is_dirty {
            self.x = x;
            self.y = y;
            self.width = w;
            self.height = h;
            self.is_dirty = true;
        } else {
            let new_min_x = self.x.min(x);
            let new_min_y = self.y.min(y);
            let new_max_x = (self.x + self.width).max(x + w);
            let new_max_y = (self.y + self.height).max(y + h);
            self.x = new_min_x;
            self.y = new_min_y;
            self.width = new_max_x - new_min_x;
            self.height = new_max_y - new_min_y;
        }
    }

    pub fn clear(&mut self) {
        self.is_dirty = false;
        self.x = 0;
        self.y = 0;
        self.width = 0;
        self.height = 0;
    }

    pub fn mark_full(&mut self, width: u32, height: u32) {
        self.x = 0;
        self.y = 0;
        self.width = width;
        self.height = height;
        self.is_dirty = true;
    }
}

impl Default for DirtyRect {
    fn default() -> Self {
        Self::new()
    }
}

impl Default for Canvas {
    fn default() -> Self {
        Self {
            width: 1280,
            height: 720,
            background_color: Color::WHITE,
            layers: vec![Layer::new("Background".to_string(), 1280, 720, 1.0)],
            active_layer: 0,
            version: 0,
            dirty_rect: DirtyRect::new(),
        }
    }
}

impl Canvas {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn with_size(width: u32, height: u32) -> Self {
        let mut canvas = Self::new();
        canvas.resize(width, height);
        canvas
    }

    pub fn version(&self) -> u64 {
        self.version
    }

    pub fn width(&self) -> u32 {
        self.width
    }

    pub fn height(&self) -> u32 {
        self.height
    }

    pub fn active_layer_index(&self) -> usize {
        self.active_layer
    }

    pub fn invalidate(&mut self) {
        self.version += 1;
        self.dirty_rect.mark_full(self.width, self.height);
    }

    pub fn mark_dirty(&mut self, x: u32, y: u32) {
        self.version += 1;
        self.dirty_rect.mark_pixel(x, y);
    }

    pub fn mark_dirty_rect(&mut self, x: u32, y: u32, w: u32, h: u32) {
        self.version += 1;
        self.dirty_rect.mark_rect(x, y, w, h);
    }

    pub fn dirty_rect(&self) -> &DirtyRect {
        &self.dirty_rect
    }

    pub fn consume_dirty_rect(&mut self) -> DirtyRect {
        let dirty = self.dirty_rect;
        self.dirty_rect.clear();
        dirty
    }

    pub fn resize(&mut self, width: u32, height: u32) {
        self.width = width;
        self.height = height;
        for layer in &mut self.layers {
            layer.content.resize(width, height);
        }
        self.invalidate();
    }

    pub fn set_background(&mut self, color: Color) {
        self.background_color = color;
        self.invalidate();
    }

    pub fn clear(&mut self) {
        for layer in &mut self.layers {
            layer.clear();
        }
        self.invalidate();
    }

    pub fn size(&self) -> (u32, u32) {
        (self.width, self.height)
    }

    pub fn background_color(&self) -> Color {
        self.background_color
    }

    pub fn layers(&self) -> &[Layer] {
        &self.layers
    }

    pub fn layers_mut(&mut self) -> &mut [Layer] {
        &mut self.layers
    }

    pub fn layer_count(&self) -> usize {
        self.layers.len()
    }

    pub fn active_layer(&self) -> usize {
        self.active_layer
    }

    pub fn set_active_layer(&mut self, index: usize) -> Result<(), String> {
        if index >= self.layers.len() {
            return Err("Invalid layer index".to_string());
        }
        self.active_layer = index;
        Ok(())
    }

    pub fn add_layer(&mut self, name: Option<String>) -> Result<usize, String> {
        const MAX_LAYERS: usize = 20;
        if self.layers.len() >= MAX_LAYERS {
            return Err("Maximum number of layers reached".to_string());
        }
        let layer_name = name.unwrap_or_else(|| format!("Layer {}", self.layers.len()));
        self.layers.push(Layer::new(layer_name, self.width, self.height, 1.0));
        self.invalidate();
        Ok(self.layers.len() - 1)
    }

    pub fn remove_layer(&mut self, index: usize) -> Result<(), String> {
        if index == 0 {
            return Err("Cannot remove background layer".to_string());
        }
        if index >= self.layers.len() {
            return Err("Invalid layer index".to_string());
        }
        self.layers.remove(index);
        if self.active_layer >= self.layers.len() {
            self.active_layer = self.layers.len() - 1;
        }
        self.invalidate();
        Ok(())
    }

    pub fn move_layer(&mut self, from: usize, to: usize) -> Result<(), String> {
        if from >= self.layers.len() || to >= self.layers.len() {
            return Err("Invalid layer index".to_string());
        }
        let layer = self.layers.remove(from);
        self.layers.insert(to, layer);
        if self.active_layer == from {
            self.active_layer = to;
        }
        self.invalidate();
        Ok(())
    }

    pub fn toggle_layer_visibility(&mut self, index: usize) -> Result<(), String> {
        if index >= self.layers.len() {
            return Err("Invalid layer index".to_string());
        }
        self.layers[index].visible = !self.layers[index].visible;
        self.invalidate();
        Ok(())
    }

    pub fn set_layer_opacity(&mut self, index: usize, opacity: f32) -> Result<(), String> {
        if index >= self.layers.len() {
            return Err("Invalid layer index".to_string());
        }
        self.layers[index].opacity = opacity.clamp(0.0, 1.0);
        self.invalidate();
        Ok(())
    }

    pub fn toggle_layer_lock(&mut self, index: usize) -> Result<(), String> {
        if index >= self.layers.len() {
            return Err("Invalid layer index".to_string());
        }
        self.layers[index].locked = !self.layers[index].locked;
        self.invalidate();
        Ok(())
    }

    pub fn clear_layer(&mut self, index: usize) -> Result<(), String> {
        if index >= self.layers.len() {
            return Err("Invalid layer index".to_string());
        }
        self.layers[index].clear();
        Ok(())
    }

    pub fn active_layer_mut(&mut self) -> &mut Layer {
        &mut self.layers[self.active_layer]
    }

    pub fn is_active_layer_locked(&self) -> bool {
        self.layers[self.active_layer].locked
    }
}

//! Undo/redo commands for canvas operations
//!
//! Each command implements the `undo::Edit` trait, providing `edit()` and `undo()` methods.

use undo::Edit;

use crate::canvas::{Canvas, Layer};

/// Enum wrapping all canvas commands for use with a single Record
#[derive(Debug, Clone)]
pub enum CanvasCommand {
    AddLayer(AddLayer),
    RemoveLayer(RemoveLayer),
    ToggleVisibility(ToggleVisibility),
    SetOpacity(SetOpacity),
}

impl Edit for CanvasCommand {
    type Target = Canvas;
    type Output = Result<(), String>;

    fn edit(&mut self, target: &mut Canvas) -> Self::Output {
        match self {
            CanvasCommand::AddLayer(cmd) => cmd.edit(target),
            CanvasCommand::RemoveLayer(cmd) => cmd.edit(target),
            CanvasCommand::ToggleVisibility(cmd) => {
                cmd.edit(target);
                Ok(())
            }
            CanvasCommand::SetOpacity(cmd) => {
                cmd.edit(target);
                Ok(())
            }
        }
    }

    fn undo(&mut self, target: &mut Canvas) -> Self::Output {
        match self {
            CanvasCommand::AddLayer(cmd) => cmd.undo(target),
            CanvasCommand::RemoveLayer(cmd) => cmd.undo(target),
            CanvasCommand::ToggleVisibility(cmd) => {
                cmd.undo(target);
                Ok(())
            }
            CanvasCommand::SetOpacity(cmd) => {
                cmd.undo(target);
                Ok(())
            }
        }
    }
}

/// Command to add a new layer to the canvas
#[derive(Debug, Clone, Default)]
pub struct AddLayer {
    name: Option<String>,
    layer: Option<Layer>,
    insertion_index: Option<usize>,
}

impl AddLayer {
    pub fn new(name: Option<String>) -> Self {
        Self { name, layer: None, insertion_index: None }
    }
}

impl Edit for AddLayer {
    type Target = Canvas;
    type Output = Result<(), String>;

    fn edit(&mut self, target: &mut Canvas) -> Self::Output {
        let idx = target.add_layer(self.name.clone())?;
        self.layer = Some(target.layers[idx].clone());
        self.insertion_index = Some(idx);
        Ok(())
    }

    fn undo(&mut self, target: &mut Canvas) -> Self::Output {
        if let Some(idx) = self.insertion_index {
            if idx < target.layers.len() {
                self.insertion_index = None;
                self.layer = None;
                target.remove_layer(idx)
            } else {
                Ok(())
            }
        } else {
            Ok(())
        }
    }
}

/// Command to remove a layer from the canvas
#[derive(Debug, Clone)]
pub struct RemoveLayer {
    index: usize,
    layer: Option<Layer>,
}

impl RemoveLayer {
    pub fn new(index: usize) -> Self {
        Self { index, layer: None }
    }
}

impl Edit for RemoveLayer {
    type Target = Canvas;
    type Output = Result<(), String>;

    fn edit(&mut self, target: &mut Canvas) -> Self::Output {
        self.layer = Some(target.layers[self.index].clone());
        target.remove_layer(self.index)
    }

    fn undo(&mut self, target: &mut Canvas) -> Self::Output {
        if let Some(layer) = self.layer.take() {
            target.layers.insert(self.index, layer);
            target.invalidate();
            Ok(())
        } else {
            Err("No layer to restore".to_string())
        }
    }
}

/// Command to toggle layer visibility
#[derive(Debug, Clone)]
pub struct ToggleVisibility {
    index: usize,
    was_visible: bool,
}

impl ToggleVisibility {
    pub fn new(index: usize) -> Self {
        Self {
            index,
            was_visible: true,
        }
    }
}

impl Edit for ToggleVisibility {
    type Target = Canvas;
    type Output = ();

    fn edit(&mut self, target: &mut Canvas) -> Self::Output {
        if self.index < target.layers.len() {
            self.was_visible = target.layers[self.index].visible;
        }
        let _ = target.toggle_layer_visibility(self.index);
    }

    fn undo(&mut self, target: &mut Canvas) -> Self::Output {
        if self.index < target.layers.len() {
            target.layers[self.index].visible = self.was_visible;
            target.invalidate();
        }
    }
}

/// Command to set layer opacity
#[derive(Debug, Clone)]
pub struct SetOpacity {
    index: usize,
    old_opacity: f32,
    new_opacity: f32,
}

impl SetOpacity {
    pub fn new(index: usize, opacity: f32) -> Self {
        Self {
            index,
            old_opacity: 1.0,
            new_opacity: opacity,
        }
    }
}

impl Edit for SetOpacity {
    type Target = Canvas;
    type Output = ();

    fn edit(&mut self, target: &mut Canvas) -> Self::Output {
        if self.index < target.layers.len() {
            self.old_opacity = target.layers[self.index].opacity;
        }
        let _ = target.set_layer_opacity(self.index, self.new_opacity);
    }

    fn undo(&mut self, target: &mut Canvas) -> Self::Output {
        if self.index < target.layers.len() {
            target.layers[self.index].opacity = self.old_opacity;
            target.invalidate();
        }
    }
}

use crate::canvas::Canvas;

/// Result of compositing all visible layers
#[derive(Debug, Clone)]
pub struct CompositeResult {
    pub width: u32,
    pub height: u32,
    pub data: Vec<u8>,
}

fn blend_pixel(dst: &mut [u8], src_r: f32, src_g: f32, src_b: f32, src_a: f32) {
    let dst_r = dst[0] as f32 / 255.0;
    let dst_g = dst[1] as f32 / 255.0;
    let dst_b = dst[2] as f32 / 255.0;
    let dst_a = dst[3] as f32 / 255.0;

    let out_a = src_a + dst_a * (1.0 - src_a);
    let inv_dst_a = 1.0 - src_a;

    let out_r = (src_r * src_a + dst_r * dst_a * inv_dst_a) / out_a;
    let out_g = (src_g * src_a + dst_g * dst_a * inv_dst_a) / out_a;
    let out_b = (src_b * src_a + dst_b * dst_a * inv_dst_a) / out_a;

    dst[0] = (out_r * 255.0).clamp(0.0, 255.0) as u8;
    dst[1] = (out_g * 255.0).clamp(0.0, 255.0) as u8;
    dst[2] = (out_b * 255.0).clamp(0.0, 255.0) as u8;
    dst[3] = (out_a * 255.0).clamp(0.0, 255.0) as u8;
}

pub struct Compositor {
    last_composited_version: u64,
    has_composited: bool,
}

impl Compositor {
    pub fn new() -> Self {
        Self {
            last_composited_version: 0,
            has_composited: false,
        }
    }

    pub fn composite_all(&self, canvas: &Canvas) -> CompositeResult {
        let pixel_count = (canvas.width * canvas.height) as usize;
        let mut data = vec![0u8; pixel_count * 4];

        for i in 0..pixel_count {
            data[i * 4] = canvas.background_color.r;
            data[i * 4 + 1] = canvas.background_color.g;
            data[i * 4 + 2] = canvas.background_color.b;
            data[i * 4 + 3] = 255;
        }

        for layer in &canvas.layers {
            if !layer.visible {
                continue;
            }

            let opacity = layer.opacity;
            let layer_data = &layer.content.data;

            for i in 0..pixel_count {
                let src_r = layer_data[i * 4] as f32 / 255.0;
                let src_g = layer_data[i * 4 + 1] as f32 / 255.0;
                let src_b = layer_data[i * 4 + 2] as f32 / 255.0;
                let src_a = (layer_data[i * 4 + 3] as f32 / 255.0) * opacity;

                if src_a <= 0.0 {
                    continue;
                }

                blend_pixel(&mut data[i * 4..i * 4 + 4], src_r, src_g, src_b, src_a);
            }
        }

        CompositeResult {
            width: canvas.width,
            height: canvas.height,
            data,
        }
    }

    pub fn composite_rect(&self, canvas: &Canvas, x: u32, y: u32, w: u32, h: u32) -> CompositeResult {
        if w == 0 || h == 0 {
            return CompositeResult {
                width: 0,
                height: 0,
                data: Vec::new(),
            };
        }

        let x = x.min(canvas.width);
        let y = y.min(canvas.height);
        let w = w.min(canvas.width - x);
        let h = h.min(canvas.height - y);

        let pixel_count = (w * h) as usize;
        let mut data = vec![0u8; pixel_count * 4];

        for i in 0..pixel_count {
            data[i * 4] = canvas.background_color.r;
            data[i * 4 + 1] = canvas.background_color.g;
            data[i * 4 + 2] = canvas.background_color.b;
            data[i * 4 + 3] = 255;
        }

        for layer in &canvas.layers {
            if !layer.visible {
                continue;
            }

            let opacity = layer.opacity;
            let layer_data = &layer.content.data;
            let layer_width = layer.content.width;

            for cy in 0..h {
                for cx in 0..w {
                    let canvas_x = x + cx;
                    let canvas_y = y + cy;

                    let out_idx = ((cy * w + cx) * 4) as usize;
                    let layer_idx = ((canvas_y * layer_width + canvas_x) * 4) as usize;

                    let src_r = layer_data[layer_idx] as f32 / 255.0;
                    let src_g = layer_data[layer_idx + 1] as f32 / 255.0;
                    let src_b = layer_data[layer_idx + 2] as f32 / 255.0;
                    let src_a = (layer_data[layer_idx + 3] as f32 / 255.0) * opacity;

                    if src_a <= 0.0 {
                        continue;
                    }

                    blend_pixel(&mut data[out_idx..out_idx + 4], src_r, src_g, src_b, src_a);
                }
            }
        }

        CompositeResult {
            width: w,
            height: h,
            data,
        }
    }

    /// Returns (CompositeResult, x_offset, y_offset) where x/y is the position
    /// of the composited region within the canvas.
    /// Full-canvas composites have (0, 0); partial composites have the dirty rect origin.
    pub fn render(&mut self, canvas: &mut Canvas) -> Option<(CompositeResult, u32, u32)> {
        let current_version = canvas.version();

        if !self.has_composited {
            self.has_composited = true;
            self.last_composited_version = current_version;
            let result = self.composite_all(canvas);
            canvas.consume_dirty_rect();
            return Some((result, 0, 0));
        }

        if current_version == self.last_composited_version {
            return None;
        }

        self.last_composited_version = current_version;
        let dirty = *canvas.dirty_rect();

        let (result, x, y) = if !dirty.is_empty()
            && (dirty.width as u64 * dirty.height as u64)
                < (canvas.width as u64 * canvas.height as u64 / 2)
        {
            (self.composite_rect(canvas, dirty.x, dirty.y, dirty.width, dirty.height), dirty.x, dirty.y)
        } else {
            (self.composite_all(canvas), 0, 0)
        };

        canvas.consume_dirty_rect();
        Some((result, x, y))
    }
}

impl Default for Compositor {
    fn default() -> Self {
        Self::new()
    }
}

//! AppEvent enum — translated from SDL2 events to domain events
//!
//! This module defines the events that the AppState handles,
//! decoupled from SDL2's event representation.

/// Events that AppState can handle
#[derive(Debug, Clone, PartialEq)]
pub enum AppEvent {
    /// Mouse button pressed at position
    Press { x: f32, y: f32 },
    /// Mouse dragged to new position
    Drag { x: f32, y: f32 },
    /// Mouse button released at position
    Release { x: f32, y: f32 },
    /// Keyboard event
    Key { code: String },
    /// Window resized to new dimensions
    Resize { width: u32, height: u32 },
    /// Mouse wheel scrolled at position; positive delta = zoom in, negative = zoom out
    Wheel { x: f32, y: f32, delta: i32 },
    /// Canvas panned by delta pixels (space+drag or middle-mouse)
    Pan { dx: f32, dy: f32 },
    /// Application quit requested
    Quit,
}

